-- FSI_DEMO_DB_V3.INSURANCE.CUSTOMER_EMAILS

CREATE OR REPLACE TABLE FSI_DEMO_DB_V3.INSURANCE.CUSTOMER_EMAILS (

    EMAIL_ID VARCHAR(20) NOT NULL,
    POLICYHOLDER_ID VARCHAR(20),
    POLICY_ID VARCHAR(20),
    EMAIL_DATE TIMESTAMP_NTZ(9),
    DIRECTION VARCHAR(10),
    FROM_ADDRESS VARCHAR(200),
    TO_ADDRESS VARCHAR(200),
    SUBJECT VARCHAR(300),
    BODY VARCHAR(16777216),
    CATEGORY VARCHAR(50),
    INTENT VARCHAR(50),
    SENTIMENT_SCORE NUMBER(5,4),
    SENTIMENT_LABEL VARCHAR(20),
    URGENCY VARCHAR(20),
    REQUIRES_RESPONSE BOOLEAN,
    RESPONSE_TIME_HOURS NUMBER(6,2),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (EMAIL_ID)

);



