INSERT INTO FSI_DEMO_DB_V3.INSURANCE.CUSTOMER_EMAILS (EMAIL_ID, POLICYHOLDER_ID, POLICY_ID, EMAIL_DATE, DIRECTION, FROM_ADDRESS, TO_ADDRESS, SUBJECT, BODY, CATEGORY, INTENT, SENTIMENT_SCORE, SENTIMENT_LABEL, URGENCY, REQUIRES_RESPONSE, RESPONSE_TIME_HOURS, CREATED_AT) VALUES
('EM00000000', 'PH00000000', 'POL00000000', '2026-02-17 14:29:50.074', 'INBOUND', 'customer0@email.com', 'claims@insurance.com', 'Question about my claim status', 'Hello, I filed a claim last week (claim number CLM-00000000) and havent heard anything since. Can you please provide an update on the status? Im concerned about the timeline as I need to get my car repaired soon. Thank you for your help.', 'CLAIMS', 'STATUS_INQUIRY', '0.1000', 'NEUTRAL', 'LOW', TRUE, '2.50', '2026-02-17 14:29:50.074'),
('EM00000001', 'PH00000001', 'POL00000002', '2026-02-17 13:39:50.074', 'INBOUND', 'customer1@email.com', 'support@insurance.com', 'URGENT: Need to file a claim', 'I need to file a claim IMMEDIATELY. My car was hit while parked overnight. There is significant damage to the drivers side door and fender. Please call me as soon as possible at (555) 123-4567. This is urgent as I need the vehicle for work. Policy number: POL-00000002', 'CLAIMS', 'FILE_CLAIM', '0.1100', 'NEUTRAL', 'HIGH', TRUE, '3.00', '2026-02-17 14:29:50.074'),
('EM00000002', 'PH00000002', 'POL00000004', '2026-02-17 12:49:50.074', 'OUTBOUND', 'claims@insurance.com', 'customer2@email.com', 'Billing inquiry - payment not reflected', 'I made my premium payment of $102 on the 15th but its still showing as unpaid on my account. I have the bank confirmation showing the payment was processed. Can you please look into this? I dont want my policy to lapse due to your error.', 'BILLING', 'PAYMENT_ISSUE', '0.1200', 'NEUTRAL', 'LOW', FALSE, NULL, '2026-02-17 14:29:50.074'),
('EM00000003', 'PH00000003', 'POL00000006', '2026-02-17 11:59:50.074', 'INBOUND', 'customer3@email.com', 'claims@insurance.com', 'Request to update policy information', 'Hi, I recently moved to a new address and need to update my policy. My new address is 456 Oak Street, Apt 7B, New York, NY 10001. Also, my phone number has changed to (555) 987-6543. Please update your records and send me a confirmation.', 'POLICY_SERVICE', 'UPDATE_INFO', '0.1300', 'NEUTRAL', 'LOW', TRUE, '4.00', '2026-02-17 14:29:50.074'),
('EM00000004', 'PH00000004', 'POL00000008', '2026-02-17 11:09:50.074', 'INBOUND', 'customer4@email.com', 'support@insurance.com', 'Extremely disappointed with service', 'I am EXTREMELY disappointed with how my claim has been handled. It has been over a month and I still dont have resolution. Every time I call I get transferred to different people and no one can help me. This is unacceptable customer service. I am considering switching to another insurance company. Someone needs to call me TODAY to resolve this.', 'COMPLAINT', 'ESCALATION', '-0.7600', 'NEGATIVE', 'HIGH', TRUE, '4.50', '2026-02-17 14:29:50.074'),
('EM00000005', 'PH00000005', 'POL00000010', '2026-02-17 10:19:50.074', 'OUTBOUND', 'claims@insurance.com', 'customer5@email.com', 'Thank you for the quick resolution', 'I just wanted to send a quick note to thank your team for the excellent service on my recent claim. Sarah from the claims department was incredibly helpful and professional. The entire process was smooth and the check arrived faster than expected. Its nice to know my insurance company is there when I need them!', 'FEEDBACK', 'POSITIVE_FEEDBACK', '0.9000', 'POSITIVE', 'LOW', FALSE, NULL, '2026-02-17 14:29:50.074'),
('EM00000006', 'PH00000006', 'POL00000012', '2026-02-17 09:29:50.074', 'INBOUND', 'customer6@email.com', 'claims@insurance.com', 'Coverage question for upcoming trip', 'Hi, Im planning a trip to Europe next month and wanted to confirm what coverage I have while traveling abroad. Specifically, does my auto policy cover rental cars in foreign countries? If not, what additional coverage would you recommend? Thanks!', 'COVERAGE_INQUIRY', 'COVERAGE_QUESTION', '0.1600', 'NEUTRAL', 'LOW', TRUE, '5.50', '2026-02-17 14:29:50.074'),
('EM00000007', 'PH00000007', 'POL00000014', '2026-02-17 08:39:50.074', 'INBOUND', 'customer7@email.com', 'support@insurance.com', 'Cancellation request', 'Please cancel my policy effective at the end of this month. I have found coverage elsewhere at a better rate. Please confirm the cancellation and any refund I may be entitled to for the unused premium portion. My policy number is POL-00000014', 'CANCELLATION', 'CANCEL_POLICY', '-0.2300', 'NEUTRAL', 'LOW', TRUE, '6.00', '2026-02-17 14:29:50.074'),
('EM00000008', 'PH00000008', 'POL00000016', '2026-02-17 07:49:50.074', 'OUTBOUND', 'claims@insurance.com', 'customer8@email.com', 'RE: Your claim has been approved', 'Dear Valued Customer, We are pleased to inform you that your claim CLM-00000008 has been approved. The settlement amount of $2008 will be deposited to your account within 5-7 business days. Thank you for your patience throughout this process. Please dont hesitate to contact us if you have any questions.', 'CLAIMS', 'NOTIFICATION', '0.6800', 'POSITIVE', 'LOW', FALSE, NULL, '2026-02-17 14:29:50.074'),
('EM00000009', 'PH00000009', 'POL00000018', '2026-02-17 06:59:50.074', 'INBOUND', 'customer9@email.com', 'claims@insurance.com', 'Documents attached as requested', 'As requested, please find attached the following documents: 1) Police report 2) Photos of damage 3) Repair estimate from ABC Auto Body. Let me know if you need anything else to process my claim. Looking forward to hearing from you soon.', 'GENERAL', 'GENERAL_INQUIRY', '0.1900', 'NEUTRAL', 'LOW', TRUE, '7.00', '2026-02-17 14:29:50.074'),
('EM00000010', 'PH00000010', 'POL00000020', '2026-02-17 06:09:50.074', 'INBOUND', 'customer10@email.com', 'support@insurance.com', 'Appeal of claim denial', 'I am writing to formally appeal the denial of my claim CLM-00000010. I believe this decision was made in error. The damage occurred through no fault of my own and is clearly covered under my policy terms. I have attached additional documentation supporting my case. Please review and reconsider this decision.', 'CLAIMS', 'STATUS_INQUIRY', '-0.4000', 'NEGATIVE', 'MEDIUM', TRUE, '7.50', '2026-02-17 14:29:50.074'),
