('EM00001998', 'PH00001998', 'POL00003996', '2025-12-10 05:29:50.074', 'INBOUND', 'customer1998@email.com', 'claims@insurance.com', 'Request to update policy information', 'Hi, I recently moved to a new address and need to update my policy. My new address is 456 Oak Street, Apt 7B, New York, NY 10001. Also, my phone number has changed to (555) 987-6543. Please update your records and send me a confirmation.', 'CLAIMS', 'NOTIFICATION', '0.4800', 'NEUTRAL', 'LOW', TRUE, '11.50', '2026-02-17 14:29:50.074'),
('EM00001999', 'PH00001999', 'POL00003998', '2025-12-10 04:39:50.074', 'INBOUND', 'customer1999@email.com', 'support@insurance.com', 'Extremely disappointed with service', 'I am EXTREMELY disappointed with how my claim has been handled. It has been over a month and I still dont have resolution. Every time I call I get transferred to different people and no one can help me. This is unacceptable customer service. I am considering switching to another insurance company. Someone needs to call me TODAY to resolve this.', 'GENERAL', 'GENERAL_INQUIRY', '-0.7600', 'NEGATIVE', 'HIGH', TRUE, '12.00', '2026-02-17 14:29:50.074');
